### Swift For-In Loops

The `for-in` loop iterates over sequences like arrays, ranges, dictionaries, and strings. It is the most commonly used loop in Swift.

**For-In Syntax:**

```swift
for item in collection {
    // Use item
}
```

**Iterating Over Ranges:**

```swift
// Closed range (includes 5)
for i in 1...5 {
    print(i)  // 1, 2, 3, 4, 5
}

// Half-open range (excludes 5)
for i in 0..<5 {
    print(i)  // 0, 1, 2, 3, 4
}

// Using stride
for i in stride(from: 0, to: 10, by: 2) {
    print(i)  // 0, 2, 4, 6, 8
}
```

**Iterating Collections:**

```swift
let fruits = ["Apple", "Banana", "Cherry"]
for fruit in fruits {
    print(fruit)
}

// With index
for (index, fruit) in fruits.enumerated() {
    print("\(index): \(fruit)")
}

// Dictionary iteration
let scores = ["Alice": 95, "Bob": 87]
for (name, score) in scores {
    print("\(name): \(score)")
}
```

> **Key Point:** Use `_` as the loop variable name if you don't need the value: `for _ in 1...10 { }`.

```swift
// Ignoring values
for _ in 1...3 {
    print("Repeating...")
}

// Where clause to filter
for i in 1...10 where i.isMultiple(of: 2) {
    print(i)  // Even numbers
}
```

codeExample:
import Foundation

// Basic range iteration
print("Counting to 5:")
for i in 1...5 {
    print(i, terminator: " ")
}
print()

// Array iteration
let names = ["Alice", "Bob", "Charlie"]
print("\nNames:")
for name in names {
    print("Hello, \(name)!")
}

// Enumerated iteration
print("\nEnumerated:")
for (index, name) in names.enumerated() {
    print("\(index + 1). \(name)")
}

// Where clause
print("\nEven numbers up to 10:")
for i in 1...10 where i % 2 == 0 {
    print(i, terminator: " ")
}
print()
